import { cfg } from './db.mjs';

export async function ensureSchema(db) {
  await db.query(`CREATE SCHEMA IF NOT EXISTS "${cfg.schema}"`);
  await db.query(`
    CREATE TABLE IF NOT EXISTS accounts (
      account_id TEXT PRIMARY KEY,
      doc JSONB NOT NULL
    )
  `);
}

export async function createAccounts(client, data) {
  const doc = {
    accountId: data.accountId,
    name: data.name,
    tier: data.tier,
    status: data.status,
    createdAt: new Date().toISOString(),
  };
  await client.query(
    'INSERT INTO accounts (account_id, doc) VALUES ($1, $2)',
    [doc.accountId, JSON.stringify(doc)]
  );
  return doc;
}

export async function getAccounts(client, accountId) {
  const result = await client.query(
    'SELECT doc FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return result.rows[0]?.doc ?? null;
}

export async function updateAccounts(client, accountId, updates) {
  const result = await client.query(
    'UPDATE accounts SET doc = doc || $2 WHERE account_id = $1 RETURNING doc',
    [accountId, JSON.stringify(updates)]
  );
  return result.rows[0]?.doc ?? null;
}

export async function deleteAccounts(client, accountId) {
  const result = await client.query(
    'DELETE FROM accounts WHERE account_id = $1',
    [accountId]
  );
  return result.rowCount > 0;
}
